valueString.value:
/*
@internal: BCG containing Doses Administered to Patient that are in the Primary series
*/
define "BCG Primary Series Doses Administered to Patient":
  "BCG Doses Administered to Patient".seriesPrimary()

/*
@internal: BCG containing Doses Administered to Patient that are in the Primary series
*/
define "BCG Primary Series Doses Administered to Patient":
  BCGElements."BCG Primary Series Doses Administered to Patient".onOrBefore(Today)

/*
@internal: Number of BCG Primary Series doses
*/
define "Number of BCG Primary Series Doses Administered":
  Count("BCG Primary Series Doses Administered to Patient")

/*
@input: No BCG primary series dose was administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "BCG vaccines" and "Type of dose" = "Primary series") = 0
@code: No BCG primary series dose was administered-112
@decision: IMMZ.D2.DT.BCG
*/
define "No BCG primary series dose was administered":
  "Number of BCG Primary Series Doses Administered" = 0

/*
@input: Client's age is less than or equal to 28 days
@pseudocode: Today's date − "Date of birth" ≤ 28 days
@code: Client's age is less than or equal to 28 days-40
@decision: IMMZ.D2.DT.BCG
*/
define "Client's age is less than or equal to 28 days":
  Encounter."Current Patient Age In Days" <= 28

/*
@internal: HIV Status Observation
*/
define "HIV status Observation":
  ([Observation: Concepts."HIV status"]).complete()

/*
@input: Client's HIV status is positive
@pseudocode: "HIV status" = "HIV-positive"
*/
define "Client's HIV status is positive":
  exists( (Elements."HIV status Observation".encounterOrOnBefore(EncounterId, Today)) O
    where O.value ~ Concepts."HIV-positive" )

/*
@input: Client's HIV status is negative or unknown
@pseudocode: "HIV status" ≠ "HIV-positive"
*/
define "Client's HIV status is negative or unknown":
  not "Client's HIV status is positive"

/*
@input: Client's HIV status is negative or unknown
@pseudocode: "HIV status" ≠ "HIV-positive"
@code: Client's HIV status is negative or unknown-29
@decision: IMMZ.D2.DT.BCG
*/
define "Client's HIV status is negative or unknown":
  Encounter."Client's HIV status is negative or unknown"

/*
  @dataElement: Live attenuated vaccines
*/
define "Live Attenuated Vaccines":
  "Doses Administered to Patient" I 
    where I.vaccineCode in Concepts."Live Attenuated"

/*
@dataElement Live attenuated vaccines
*/
define "Live Attenuated Vaccines":
  Elements."Live Attenuated Vaccines" I
    where I.occurrence.toInterval() same day or before Today

/*
@input: No live vaccine was administered
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) IS NULL
*/
define "No live vaccine was administered":
  not exists("Live Attenuated Vaccines")

/*
@input: No live vaccine was administered
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) IS NULL
@code: No live vaccine was administered-90
@decision: IMMZ.D2.DT.BCG
*/
define "No live vaccine was administered":
  Encounter."No live vaccine was administered"

/*
@output: Client is due for BCG vaccination Case 1
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for BCG vaccination Case 1":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is less than or equal to 28 days"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."No live vaccine was administered"

/*
@input: Client's HIV status is positive
@pseudocode: "HIV status" = "HIV-positive"
@code: Client's HIV status is positive-29
@decision: IMMZ.D2.DT.BCG
*/
define "Client's HIV status is positive":
  Encounter."Client's HIV status is positive"

/*
@internal: Currently on ART Observation
*/
define "Currently on ART Observation":
  ([Observation: Concepts."Currently on ART"] O
    sort by end of effective.toInterval() desc).complete()

/*
@internal: Currently on ART Observation
*/
define "Currently on ART Observation":
  Elements."Currently on ART Observation".encounterOrOnBefore(EncounterId, Today).mostRecent()

/*
@input: Client is currently receiving antiretroviral therapy
@pseudocode: "Currently on ART" = TRUE
*/
define "Client is currently receiving antiretroviral therapy":
  "Currently on ART Observation" is not null
  and "Currently on ART Observation".value = true

/*
@input: Client is currently receiving antiretroviral therapy
@pseudocode: "Currently on ART" = TRUE
@code: Client is currently receiving antiretroviral therapy-25
@decision: IMMZ.D2.DT.BCG
*/
define "Client is currently receiving antiretroviral therapy":
  Encounter."Client is currently receiving antiretroviral therapy"

/*
@internal: Immunologically stable Observation
*/
define "Immunologically stable Observation":
  ([Observation: Concepts."Immunologically stable"] O
    sort by end of effective.toInterval() desc).complete()

/*
@internal: Immunologically stable Observation
*/
define "Immunologically stable Observation":
  Elements."Immunologically stable Observation".encounterOrOnBefore(EncounterId, Today)

/*
@input: Client is immunologically stable
@pseudocode: "Immunologically stable" = TRUE
*/
define "Client is immunologically stable":
  exists("Immunologically stable Observation")
  and First("Immunologically stable Observation").value = true

/*
@input: Client is immunologically stable
@pseudocode: "Immunologically stable" = TRUE
@code: Client is immunologically stable-31
@decision: IMMZ.D2.DT.BCG
*/
define "Client is immunologically stable":
  Encounter."Client is immunologically stable"

/*
@input: Client's age is between 28 days and 5 years
@pseudocode: 28 days < Today's date − "Date of birth" < 5 years
@code: Client's age is between 28 days and 5 years-50
@decision: IMMZ.D2.DT.BCG
*/
define "Client's age is between 28 days and 5 years":
  28 < Encounter."Current Patient Age In Days"
  and Encounter."Current Patient Age In Years" < 5

/*
@internal: TB infection test result Observation
*/
define "TB infection test result Observation":
  ([Observation: Concepts."TB infection test result"] O
    sort by end of effective.toInterval() desc).complete()

/*
@internal: Immunologically stable Observation
*/
define "TB infection test result Observation":
  Elements."TB infection test result Observation".encounterOrOnBefore(EncounterId, Today)

/*
@input: Client's TB infection test result is negative
@pseudocode: "TB infection test result" = "Negative"
*/
define "Client's TB infection test result is negative":
  exists("TB infection test result Observation")
  and First( "TB infection test result Observation" ).value ~ Concepts."TB-Negative"

/*
@input: Client's TB infection test result is negative
@pseudocode: "TB infection test result" = "Negative"
@code: Client's TB infection test result is negative-39
@decision: IMMZ.D2.DT.BCG
*/
define "Client's TB infection test result is negative":
  Encounter."Client's TB infection test result is negative"

/*
@dataElement Date and time of last live attenuated vaccine
*/
define "Date of Latest Live Attenuated Vaccine":
  date from start of "Live Attenuated Vaccines".mostRecent().occurrence.toInterval()

/*
@input: Live vaccine was administered in the last 4 weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) < 4 weeks
*/
define "Live vaccine was administered in the last 4 weeks":
	"Date of Latest Live Attenuated Vaccine" is not null 
    and duration in weeks between "Date of Latest Live Attenuated Vaccine" and Today < 4

/*
@input: No live vaccine was administered in the last 4 weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) ≥ 4 weeks
*/
define "No live vaccine was administered in the last 4 weeks":
  not("Live vaccine was administered in the last 4 weeks")

/*
@input: No live vaccine was administered in the last four weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) ≥ 4 weeks
@code: No live vaccine was administered in the last four weeks-92
@decision: IMMZ.D2.DT.BCG
*/
define "No live vaccine was administered in the last four weeks":
  Encounter."No live vaccine was administered in the last 4 weeks"

/*
@output: Client is due for BCG vaccination Case 3
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for BCG vaccination Case 3":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is negative"
    and Encounter."No live vaccine was administered in the last four weeks"

/*
@internal: Clinically well Observation
*/
define "Clinically well Observation":
  ([Observation: Concepts."Clinically well"] O
    sort by end of effective.toInterval() desc).complete()

/*
@internal: Clinically well Observation
*/
define "Clinically well Observation":
  Elements."Clinically well Observation".encounterOrOnBefore(EncounterId, Today)

/*
@input: Client is clinically well
@pseudocode: "Clinically well" = TRUE
*/
define "Client is clinically well":
  exists("Clinically well Observation")  
  and First( "Clinically well Observation" ).value = true

/*
@input: Client is clinically well
@pseudocode: "Clinically well" = TRUE
@code: Client is clinically well-24
@decision: IMMZ.D2.DT.BCG
*/
define "Client is clinically well":
  Encounter."Client is clinically well"

/*
@input: Client's age is more than 5 years
@pseudocode: Today's date − "Date of birth" ≥ 5 years
@code: Client's age is more than 5 years-40
@decision: IMMZ.D2.DT.BCG
*/
define "Client's age is more than 5 years":
  Encounter."Current Patient Age In Years" >= 5

/*
@output: Client is due for BCG vaccination Case 5
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for BCG vaccination Case 5":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is negative"
    and Encounter."No live vaccine was administered in the last four weeks"

/*
@input: Live vaccine was administered in the last four weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) < 4 weeks
@code: Live vaccine was administered in the last four weeks-92
@decision: IMMZ.D2.DT.BCG
*/
define "Live vaccine was administered in the last four weeks":
  Encounter."Live vaccine was administered in the last 4 weeks"

/*
@output: Client is not due for BCG vaccination Case 1
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 1":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is less than or equal to 28 days"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Live vaccine was administered in the last four weeks"

/*
@input: Client is not immunologically stable
@pseudocode: "Immunologically stable" = FALSE
*/
define "Client is not immunologically stable":
  exists("Immunologically stable Observation")
  and First("Immunologically stable Observation").value = false

/*
@input: Client is not immunologically stable
@pseudocode: "Immunologically stable" = FALSE
@code: Client is not immunologically stable-32
@decision: IMMZ.D2.DT.BCG
*/
define "Client is not immunologically stable":
  Encounter."Client is not immunologically stable"

/*
@output: Client is not due for BCG vaccination Case 3
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 3":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is less than or equal to 28 days"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently receiving antiretroviral therapy"
    and Encounter."Client is not immunologically stable"

/*
@input: Client is currently not receiving antiretroviral therapy
@pseudocode: "Currently on ART" = FALSE
*/
define "Client is currently not receiving antiretroviral therapy":
  "Currently on ART Observation" is null
  or "Currently on ART Observation".value = false

/*
@input: Client is currently not receiving antiretroviral therapy
@pseudocode: "Currently on ART" = FALSE
@code: Client is currently not receiving antiretroviral therapy-26
@decision: IMMZ.D2.DT.BCG
*/
define "Client is currently not receiving antiretroviral therapy":
  Encounter."Client is currently not receiving antiretroviral therapy"

/*
@output: Client is not due for BCG vaccination Case 4
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 4":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is less than or equal to 28 days"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently not receiving antiretroviral therapy"

/*
@output: Client is not due for BCG vaccination Case 5
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 5":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is negative"
    and Encounter."Live vaccine was administered in the last four weeks"

/*
@input: Client's TB infection test result is positive
@pseudocode: "TB infection test result" = "Positive"
*/
define "Client's TB infection test result is positive":
  exists("TB infection test result Observation")
  and First( "TB infection test result Observation" ).value ~ Concepts."TB-Positive"

/*
@input: Client's TB infection test result is positive
@pseudocode: "TB infection test result" = "Positive"
@code: Client's TB infection test result is positive-39
@decision: IMMZ.D2.DT.BCG
*/
define "Client's TB infection test result is positive":
  Encounter."Client's TB infection test result is positive"

/*
@output: Client is not due for BCG vaccination Case 6
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 6":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is positive"

/*
@output: Client is not due for BCG vaccination Case 7
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 7":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently receiving antiretroviral therapy"
    and Encounter."Client is not immunologically stable"

/*
@input: Client is not clinically well
@pseudocode: "Clinically well" = FALSE
*/
define "Client is not clinically well":
  exists("Clinically well Observation")  
  and First( "Clinically well Observation" ).value = false

/*
@input: Client is not clinically well
@pseudocode: "Clinically well" = FALSE
@code: Client is not clinically well-25
@decision: IMMZ.D2.DT.BCG
*/
define "Client is not clinically well":
  Encounter."Client is not clinically well"

/*
@output: Client is not due for BCG vaccination Case 8
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 8":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently receiving antiretroviral therapy"
    and Encounter."Client is not clinically well"

/*
@output: Client is not due for BCG vaccination Case 10
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 10":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently not receiving antiretroviral therapy"

/*
@output: Client is not due for BCG vaccination Case 11
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 11":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is negative"
    and Encounter."Live vaccine was administered in the last four weeks"

/*
@output: Client is not due for BCG vaccination Case 12
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 12":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is positive"

/*
@output: Client is not due for BCG vaccination Case 13
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 13":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently receiving antiretroviral therapy"
    and Encounter."Client is not immunologically stable"

/*
@output: Client is not due for BCG vaccination Case 14
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 14":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently receiving antiretroviral therapy"
    and Encounter."Client is not clinically well"

/*
@output: Client is not due for BCG vaccination Case 16
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for BCG vaccination Case 16":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is positive"
    and Encounter."Client is currently not receiving antiretroviral therapy"

/*
@input: Client's TB infection test result is unknown (test not done or no result yet)
@pseudocode: "TB infection test result" IS NULL
*/
define "Client's TB infection test result is unknown (test not done or no result yet)":
  not exists( "TB infection test result Observation" ) or (
    not ("Client's TB infection test result is negative") and not ("Client's TB infection test result is positive")
  )

/*
@input: Client's TB infection test result is unknown (test not done or no result yet)
@pseudocode: "TB infection test result" IS NULL
@code: Client's TB infection test result is unknown (test not done or no result yet)-34
@decision: IMMZ.D2.DT.BCG
*/
define "Client's TB infection test result is unknown (test not done or no result yet)":
  Encounter."Client's TB infection test result is unknown (test not done or no result yet)"

/*
@output: Clinical judgement is required. Create clinical note. Case 1
@pseudocode: "Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note. Case 1":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is between 28 days and 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is unknown (test not done or no result yet)"

/*
@output: Clinical judgement is required. Create clinical note. Case 2
@pseudocode: '"Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note. Case 2":
  Encounter."No BCG primary series dose was administered"
    and Encounter."Client's age is more than 5 years"
    and Encounter."Client's HIV status is negative or unknown"
    and Encounter."Client's TB infection test result is unknown (test not done or no result yet)"

/*
@output: Clinical judgement is required. Create clinical note.
@pseudocode: "Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note.":
  "Clinical judgement is required. Create clinical note. Case 1"
    or "Clinical judgement is required. Create clinical note. Case 2"

/*
@input: One BCG primary series dose was administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "BCG vaccines" and "Type of dose" = "Primary series") = 1
@code: One BCG primary series dose was administered-112
@decision: IMMZ.D2.DT.BCG
*/
define "One BCG primary series dose was administered":
  "Number of BCG Primary Series Doses Administered" = 1

/*
@output: BCG immunization schedule is complete
@pseudocode: '"Immunization recommendation status" = "Complete"
"Completed the primary vaccination series" = TRUE (where "Vaccine type" = "BCG vaccines")
*/
define "BCG immunization schedule is complete":
  Encounter."One BCG primary series dose was administered"

/*
@output: BCG immunization schedule is complete Guidance
@guidance: BCG immunization schedule is complete. One BCG primary series dose was administered.
Check for any vaccines due.
*/
define "BCG immunization schedule is complete Guidance":
  'BCG immunization schedule is complete. One BCG primary series dose was administered.
Check for any vaccines due.'

/*
@description: Returns true if the given reference is to the given resourceId
@comment: Returns true if the `resourceId` parameter exactly equals the tail of the given reference.
NOTE: This function assumes resources from the same source server.
*/
define fluent function references(reference FHIR.Reference, resourceId String):
  resourceId = Last(Split(reference.reference, '/'))
